#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=200005;
ll n,m,dep[N],f[N],a[N];
struct node
{
	ll v,val;
};
vector<node> g[N];
void dfs(int u,int fa,ll sum)
{
	dep[u]=sum;
	f[u]=fa;
	for(int i=0;i<g[u].size();i++)
	{
		long long v=g[u][i].v,num=g[u][i].val;
		if(v==fa) continue;
		dfs(v,u,sum+num);
	}
}
int main()
{
//	freopen("1.in","r",stdin);
//	freopen("1(my).out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		ll u,v,val;
		cin>>u>>v>>val;
		g[u].push_back(node{v,val});
		g[v].push_back(node{u,val});
	}
	dfs(1,0,0);
	ll mx=-1,mxnum=0;
	for(int i=1;i<=n;i++)
	{
		if(dep[i]>mx)
		{
			mx=dep[i];
			mxnum=i;
		}
	}
	ll x=mxnum;
	dfs(x,0,0);
	mx=-1;
	for(int i=1;i<=n;i++)
	{
		a[i]=dep[i];
		if(dep[i]>mx)
		{
			mx=dep[i];
			mxnum=i;
		}
	}
	ll y=mxnum;
	dfs(y,0,0);
	ll mxx=0;
	for(int i=1;i<=n;i++)
	{
		mxx=max(mxx,min(a[i],dep[i]));
	}
	cout<<mx+mxx;
	return 0;
}
